const b = $input.first().json.body || {};
return [{ json: {
  messageId:   b.messageId   || '',
  rLevel:      parseInt(b.rLevel || 1),
  complaintno: b.complaintno || '',
  storeName:   b.storeName   || '',
  storeCode:   b.storeCode   || '',
  productName: b.productName || '',
  newEdc:      b.newEdc      || '',
  toEmail:     b.toEmail     || '',
  ccEmails:    b.ccEmails    || '',
} }];

const prep = $('Prepare').first().json;
const allTemplates = $input.all().map(i => ({
  id:       parseInt(i.json['ID'] || 0),
  name:     i.json['Template Name'] || '',
  category: i.json['Category']      || '',
  body:     i.json['Template Body'] || '',
})).filter(t => t.id > 0 && t.name);

const rLevel = prep.rLevel || 1;
const levelStr = rLevel >= 3 ? '3' : String(rLevel);

// Find by name or category containing 'Reminder N'
let template = allTemplates.find(t =>
  t.name.toLowerCase().includes('reminder ' + levelStr) ||
  t.category.toLowerCase().includes('reminder ' + levelStr)
);
// Fallback: any reminder template
if (!template) template = allTemplates.find(t =>
  t.name.toLowerCase().includes('reminder') ||
  t.category.toLowerCase().includes('reminder')
);

const attemptLabel = rLevel === 1 ? '1st Reminder' : rLevel === 2 ? '2nd Reminder' : 'Final Reminder';
const storeDisplay = prep.storeName + (prep.storeCode ? ' (' + prep.storeCode + ')' : '');

const fallback = '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.7;max-width:700px">'
  + '<p>Dear Team,</p>'
  + '<p>This is the <strong>' + attemptLabel + '</strong> for VMM Complaint <strong>' + prep.complaintno + '</strong> — <strong>' + prep.productName + '</strong> at <strong>' + storeDisplay + '</strong>.</p>'
  + '<p>We attempted to contact you but were unable to connect. Please address this complaint at the earliest.</p>'
  + '<table style="border-collapse:collapse;margin:12px 0">'
  + '<tr><td style="padding:6px 14px;background:#f8fafc;font-weight:700;border:1px solid #e2e8f0">Complaint No</td><td style="padding:6px 14px;border:1px solid #e2e8f0;font-weight:800;color:#1e1b4b">' + prep.complaintno + '</td></tr>'
  + '<tr><td style="padding:6px 14px;background:#f8fafc;font-weight:700;border:1px solid #e2e8f0">Product</td><td style="padding:6px 14px;border:1px solid #e2e8f0">' + prep.productName + '</td></tr>'
  + '<tr><td style="padding:6px 14px;background:#f8fafc;font-weight:700;border:1px solid #e2e8f0">Revised EDC</td><td style="padding:6px 14px;border:1px solid #e2e8f0;font-weight:700;color:#dc2626">' + prep.newEdc + '</td></tr>'
  + '</table>'
  + '<p>Regards,<br>VMM Helpdesk Team<br>Open Mind Services Limited</p>'
  + '</div>';

let body = template ? template.body : fallback;

// Replace template variables — supports {{var}}, {var}, [VAR] formats
const vars = [
  ['{{complaintno}}',   prep.complaintno || ''],
  ['{complaintno}',     prep.complaintno || ''],
  ['[COMPLAINT_NO]',    prep.complaintno || ''],
  ['{{storeName}}',     prep.storeName   || ''],
  ['{storeName}',       prep.storeName   || ''],
  ['[STORE_NAME]',      prep.storeName   || ''],
  ['{{storeCode}}',     prep.storeCode   || ''],
  ['{storeCode}',       prep.storeCode   || ''],
  ['[STORE_CODE]',      prep.storeCode   || ''],
  ['{{productName}}',   prep.productName || ''],
  ['{productName}',     prep.productName || ''],
  ['[PRODUCT_NAME]',    prep.productName || ''],
  ['{{newEdc}}',        prep.newEdc      || ''],
  ['{newEdc}',          prep.newEdc      || ''],
  ['[NEW_EDC]',         prep.newEdc      || ''],
  ['{{rLevel}}',        String(rLevel)],
  ['{{attempt}}',       attemptLabel],
  ['[ATTEMPT]',         attemptLabel],
];
for (const [k, v] of vars) body = body.split(k).join(v);

return [{ json: { ...prep, htmlBody: body } }];
